#include <iostream>
using namespace std;
int main() {
    int y = 0, m = 0;
    cin >> y >> m;                    // 读入年份 y 和月份 m
    bool leap = false;                // 闰年标志,先假设不是闰年
    if (y % 400 == 0)                 // 规则一:能被 400 整除 → 闰年(如 2000)
        leap = true;
    if (y % 4 == 0 && y % 100 != 0)   // 规则二:能被 4 整除但不能被 100 整除 → 闰年
        leap = true;                  // (1900 被 100 整除,所以不是闰年)
    if (m ==1 || m==3 || m==5 || m==7 || m==8 || m==10 || m==12)
        cout << 31 << endl;           // 大月:1、3、5、7、8、10、12 月都是 31 天
    else if (m == 4 || m == 6 || m == 9 || m == 11)
        cout << 30 << endl;           // 小月:4、6、9、11 月都是 30 天
    else if (leap)                    // 剩下的只能是 2 月:闰年 29 天
        cout << 29 << endl;
    else                              // 平年 2 月 28 天
        cout << 28 << endl;
    return 0;
}

#include <iostream>
using namespace std;
int main() {
    int area = 0, cnt = 0;            // area:面积  cnt:方案计数器
    cin >> area;                      // 读入长方形面积
    for (int w = 1; w * w <= area; w++) {  // 枚举宽 w;条件 w*w<=area 保证 宽≤长,不重复计数
        if (area % w == 0)            // w 能整除面积 → 对应的长是 area/w,是一种合法方案
            cnt++;                    // 计数加一
    }
    cout << cnt << endl;              // 输出方案总数
    return 0;
}

