#include <stdio.h>

int main(int argc, char **argv)
{
    int x, n;
    scanf("%d%d", &x, &n);            // 读入今天星期 x 和距考试天数 n
    printf("%d\n", (x-1+n%7)%7+1);
    // 核心一行,拆开看:
    //   x-1      → 把星期 1~7 映射到 0~6,方便取余
    //   + n%7    → 加上 n 天的有效偏移(整周不影响星期)
    //   %7       → 对 7 取余,回到 0~6
    //   +1       → 映射回 1~7(题目用 7 表示星期日)
    // "先减一、取余、再加一"是处理 1 开头编号周期问题的标准手法
    return 0;
}

#include <cstdio>
using namespace std;
int main() {
    double K; scanf("%lf", &K);       // 用 double 读入开尔文温度(实数必须用浮点类型)
    double C = K - 273.15;            // 公式一:摄氏 = 开尔文 - 273.15
    double F = 32 + C * 1.8;          // 公式二:华氏 = 摄氏 × 1.8 + 32
    if (F > 212)                      // 华氏温度超过 212 → 输出警告语
        printf("Temperature is too high!\n");  // 必须一字不差(包括感叹号)
    else
        printf("%.2f %.2f\n", C, F); // %.2f 保留两位小数,中间一个空格
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, x, y, ans;
    cin >> n >> x >> y;               // 读入书的总数 n、啃光一本要 x 小时、经过 y 小时
    assert(1 <= n && n <= 1000 && 1 <= x && x <= 1000 && 1 <= y && y <= 1000);
                                      // assert 是数据校验,阅读时可忽略
    ans = n - y / x - 1 + (y % x == 0);
    // 拆开理解:y/x 是已经啃光的整本数
    //   若 y%x != 0:还有一本正被啃(不完整),要再减 1 → n - y/x - 1
    //   若 y%x == 0:恰好啃完、没碰下一本,(y%x==0) 为 1,把多减的 1 补回来
    // 整体等价于 n - ⌈y/x⌉(向上取整),一个表达式同时处理两种情况
    assert(ans >= 1);                 // 题目保证至少剩一本完整的书
    cout << ans << '\n';
    return 0;
}

#include <bits/stdc++.h>
