int main() {
    int n; cin >> n; assert(1 <= n && n <= 100);   // 读入数字个数(assert 是校验,可忽略)
    for (int i = 1, x; i <= n; i++) {
        cin >> x; assert(1 <= x && x <= 10000);    // 逐个读入待处理的数
        cout << (x + 5) / 10 * 10 << '\n';
        // 四舍五入到整十数的一行公式:
        //   x+5     → 个位 ≥5 时,加 5 会让十位进一(如 58+5=63)
        //   /10     → 整数除法砍掉个位(63/10=6)
        //   *10     → 乘回来得整十数(6*10=60)
        // 个位 <5 时加 5 不会进位,自动舍去(43+5=48 → 4 → 40)
    }
    return 0;
}

#include <cstdio>
using namespace std;
int n, k, t;                          // n:书的总页数  k:每天最多读 k 页  t:假期天数
int ans;
int main() {
    scanf("%d", &n);
    scanf("%d", &k);
    scanf("%d", &t);                  // 依次读入三个数
    ans = k * t;                      // 假期里"最多能读"的页数 = 每天 k 页 × t 天
    if (n < ans)                      // 但书一共只有 n 页
        ans = n;                      // 读不了比书更多的页数 → 取两者较小值
    printf("%d\n", ans);             // 即 ans = min(n, k*t)
    return 0;
}

