#include <algorithm>
#include <cstdio>
using namespace std;
int x, y, n, p;                       // 方案一:满 x 减 y;方案二:打 n 折;p:商品原价
double a1, a2;                        // 两种方案的实付金额
int main() {
    scanf("%d%d%d%d", &x, &y, &n, &p);
    a1 = p;                           // 方案一:先按原价
    if (a1 >= x) a1 -= y;             // 满足"满 x"门槛才能减 y;不满足就是原价
    a2 = p * 0.1 * n;                 // 方案二:打 n 折 = 原价 × n/10
                                      // 写成 p*0.1*n 用浮点算,避免整数除法截断
    printf("%.2lf\n", min(a1, a2));  // 输出更便宜的那个,保留两位小数
    return 0;
}

#include <algorithm>
#include <cstdio>
using namespace std;
int n, ans;                           // n:金字塔层数  ans:石块总数
int main() {
    scanf("%d", &n);
    for (int i = 1; i <= n; i++) ans += i * i;
    // 从上往下第 i 层需要 i×i 块,总数就是平方和 1²+2²+...+n²
    // n ≤ 50 时总和最大约 4.3 万,int 完全够用
    printf("%d\n", ans);
    return 0;
}

